SELECT AVG(avg_speed) AS average_speed
FROM race_stages
WHERE race_id = 1;

SELECT AVG(r.points) AS average_points, COUNT(DISTINCT r.rider_id) AS rider_count
FROM results r
WHERE r.rank = 1;

SELECT AVG(performance_improvement) AS average_performance_improvement
FROM rider_progress
WHERE season = 2023;

SELECT name
FROM riders
WHERE specialty = 'climber';

SELECT race_name
FROM races
WHERE race_id = 1;
